{
  "terms": [
    {
      "term": "Statutory Regulations",
      "simpleDefinition": "Legally binding laws passed by Parliament that must be followed by everyone in the industry.",
      "anchor": "The Law of the Land.",
      "misconception": "Believing these are just 'industry rules' rather than criminal laws."
    },
    {
      "term": "Non-statutory Regulations",
      "simpleDefinition": "Guidance documents and codes of practice that provide technical instructions on how to meet legal requirements.",
      "anchor": "The Industry's Best Practice.",
      "misconception": "Thinking that because they aren't 'law', they can be ignored without any legal consequence."
    },
    {
      "term": "BS 7671",
      "simpleDefinition": "The UK national standard for electrical installations, also known as the IET Wiring Regulations.",
      "anchor": "The Electrician's Bible.",
      "misconception": "Many beginners wrongly believe BS 7671 is a statutory law; it is actually non-statutory."
    },
    {
      "term": "EAWR (Electricity at Work Regulations)",
      "simpleDefinition": "The specific statutory law that sets out legal duties for electrical safety in the workplace.",
      "anchor": "The Electrical Law.",
      "misconception": "Confusing the EAWR (the law) with BS 7671 (the technical guidance)."
    },
    {
      "term": "HASAWA (Health and Safety at Work Act)",
      "simpleDefinition": "The primary piece of UK legislation that covers the health, safety, and welfare of people at work.",
      "anchor": "The Umbrella Act.",
      "misconception": "Thinking it only applies to employers; it actually places duties on employees (you) as well."
    },
    {
      "term": "On-Site Guide",
      "simpleDefinition": "A non-statutory handbook that provides a simplified version of BS 7671 for common installation tasks.",
      "anchor": "The Pocket Reference.",
      "misconception": "Thinking the On-Site Guide covers every possible electrical scenario; it only covers standard installations."
    },
    {
      "term": "PPE (Personal Protective Equipment)",
      "simpleDefinition": "Statutory regulations requiring equipment like boots, gloves, and goggles to protect workers from hazards.",
      "anchor": "Your Last Line of Defence.",
      "misconception": "Believing PPE is optional if the job is 'quick' or 'easy'."
    }
  ],
  "anchorPhrases": [
    "Statutory means it is the law.",
    "Non-statutory is the 'how-to' guide.",
    "BS 7671 is non-statutory guidance.",
    "EAWR is a statutory requirement.",
    "Acts and Regulations are statutory."
  ],
  "misconceptionTargets": [
    "BS 7671 is not a law, but following it helps you stay within the law.",
    "Statutory regulations cover more than just electricity; they include PPE, manual handling, and noise.",
    "You cannot pick and choose which statutory regulations to follow.",
    "Non-statutory documents are used in court to prove you worked to a safe standard."
  ]
}

{
  "teachChecks": [
    {
      "title": "Statutory Regulations",
      "objective": "Identify specific statutory regulations that govern electrical work and general safety.",
      "retrievalTextLines": [
        "Statutory regulations are the 'Law of the Land.' In the UK, these are Acts of Parliament or Regulations that you must follow by law. If you fail to comply, you are committing a criminal offense. The primary 'umbrella' law for our industry is the Health and Safety at Work Act (HASAWA), which covers the safety and welfare of everyone on a job site.",
        "For electricians, the most critical statutory document is the Electricity at Work Regulations (EAWR). This law sets out the legal duties for electrical safety in the workplace. Other statutory requirements you must follow include PPE (Personal Protective Equipment) regulations, COSHH for hazardous substances, and PUWER for the safe use of work equipment. You are also legally bound by the CDM (Construction Design and Management) regulations and the Manual Handling Operations Regulations.",
        "Statutory laws also cover broader areas, such as the Environmental Act, the Noise at Work Regulations, and the DDA (Disability Discrimination Act). Remember: if a document is statutory, it is a mandatory legal requirement, not a suggestion."
      ],
      "hint": "Focus on terms like 'Act' or 'Regulations' and remember that these are legally binding laws passed by Parliament."
    },
    {
      "title": "Non-statutory Regulations and Guidance",
      "objective": "Identify non-statutory regulations and guidance documents used in the electrical industry.",
      "retrievalTextLines": [
        "Non-statutory regulations and guidance are the industry’s 'how-to' guides. These documents are not laws passed by Parliament, but they represent best practice and technical instruction. The most famous example is BS 7671, also known as the IET Wiring Regulations or 'The Electrician's Bible.' A common misconception is that BS 7671 is a statutory law; it is actually a non-statutory national standard.",
        "While BS 7671 isn't a law itself, following it is the standard way to prove you have complied with statutory laws like the EAWR. If you end up in court, you will be judged against these standards. Other non-statutory documents include the On-Site Guide, which is a simplified pocket reference for common tasks, and the IET Guidance Notes that provide deep technical detail on specific topics.",
        "You may also use the Unite Union Book (Electrician's Guide to Good Practice) or various Codes of Practice. These documents provide the technical instructions needed to ensure your work is safe, professional, and compliant with the overarching legal requirements."
      ],
      "hint": "Look for documents like BS 7671, the On-Site Guide, or Guidance Notes, which provide technical 'best practice' rather than legal mandates."
    }
  ]
}

